import{_ as e,o as t,c as l,aQ as r}from"./chunks/framework.cDvftfeu.js";const p=JSON.parse('{"title":"予定","description":"期限リマインダーとカレンダー同期でスケジュールを管理。","frontmatter":{"description":"期限リマインダーとカレンダー同期でスケジュールを管理。"},"headers":[],"relativePath":"ja/handbook/schedule.md","filePath":"ja/handbook/schedule.md","lastUpdated":1777525243000}'),i={name:"ja/handbook/schedule.md"};function o(n,a,s,h,d,c){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="予定" tabindex="-1">予定 <a class="header-anchor" href="#予定" aria-label="Permalink to &quot;予定&quot;">​</a></h1><p>予定ページでは、すべての予定の確認、追加、削除ができます。</p><h2 id="直近の予定" tabindex="-1">直近の予定 <a class="header-anchor" href="#直近の予定" aria-label="Permalink to &quot;直近の予定&quot;">​</a></h2><p>予定ページに入ると、ページ上部に現在時刻から最も近い未期限の予定が表示されます。予定名、時間、場所、開始までのカウントダウンが含まれます。授業に紐づいている場合は、授業名も表示されます。</p><p>直近の予定カードをタップすると、詳細を確認できます。</p><h2 id="予定グループ" tabindex="-1">予定グループ <a class="header-anchor" href="#予定グループ" aria-label="Permalink to &quot;予定グループ&quot;">​</a></h2><p>グループを作成して予定を分類管理できます。グループは予定リストの上部に表示され、タップするとそのグループの予定のみが表示されます。各グループには名前とアイコンを設定できます。</p><h2 id="予定の追加" tabindex="-1">予定の追加 <a class="header-anchor" href="#予定の追加" aria-label="Permalink to &quot;予定の追加&quot;">​</a></h2><p>右上の「+」ボタンをタップして新しい予定を追加します。以下の情報を設定できます：</p><ul><li><strong>名前</strong>：予定のタイトル（必須）</li><li><strong>場所</strong>：予定の場所</li><li><strong>メモ</strong>：予定の詳細内容</li><li><strong>目標時間</strong>：予定の開始時間</li><li><strong>終了時間</strong>：任意。予定の終了時間（開始時間から24時間以内）</li><li><strong>グループ</strong>：予定をグループに分類</li><li><strong>リマインダー</strong>：予定開始前に通知。10分、30分、1時間、2時間、4時間、8時間から選択可能</li><li><strong>繰り返し</strong>：日、週、月単位の繰り返しルールを設定可能。繰り返し終了日も設定できます</li><li><strong>関連授業</strong>：時間割の授業と予定を紐づけ</li></ul><h2 id="編集と削除" tabindex="-1">編集と削除 <a class="header-anchor" href="#編集と削除" aria-label="Permalink to &quot;編集と削除&quot;">​</a></h2><p>予定リストの項目をタップすると詳細が表示されます。詳細ポップアップでは：</p><ul><li>設定ボタンをタップして予定を編集</li><li>削除ボタンをタップして予定を削除</li><li>繰り返し設定がある場合、関連するすべての繰り返し予定を削除することも可能</li></ul><h2 id="システムカレンダー連携-ios" tabindex="-1">システムカレンダー連携（iOS） <a class="header-anchor" href="#システムカレンダー連携-ios" aria-label="Permalink to &quot;システムカレンダー連携（iOS）&quot;">​</a></h2><p>予定の追加・編集後、Hamは自動的にシステムカレンダーに同期します（カレンダー名：「Ham-日程」）。予定名、場所、メモ、時間、リマインダー情報がすべて同期されます。</p><h2 id="通知リマインダー" tabindex="-1">通知リマインダー <a class="header-anchor" href="#通知リマインダー" aria-label="Permalink to &quot;通知リマインダー&quot;">​</a></h2><p>リマインダーを設定すると、予定開始前にシステム通知でお知らせします。通知には予定名、場所、開始時間が含まれます。</p><h2 id="必要な権限" tabindex="-1">必要な権限 <a class="header-anchor" href="#必要な権限" aria-label="Permalink to &quot;必要な権限&quot;">​</a></h2><h3 id="予定リマインダー" tabindex="-1">予定リマインダー <a class="header-anchor" href="#予定リマインダー" aria-label="Permalink to &quot;予定リマインダー&quot;">​</a></h3><ul><li>iOS: 通知、カレンダー</li><li>Android: 通知権限</li></ul>',20)])])}const b=e(i,[["render",o]]);export{p as __pageData,b as default};
